content.text:
/* Author normal — tier 3 */
p { color: #374151; }

/* Author !important — tier 4 — beats all author normal rules */
.error-text { color: #ef4444 !important; }

/* Declare the layer order — later = higher priority */
@layer reset, base, components, utilities;

@layer reset {
  *, *::before, *::after { box-sizing: border-box; margin: 0; }
}

@layer base {
  p { color: #374151; font-size: 1rem; }
}

@layer components {
  /* This wins over @layer base even with lower specificity */
  p { color: #1e293b; }
}

/* Unlayered styles beat all layered styles */
p { color: #000; }

/* 0,0,1,1 — one class + one type */
a.btn { color: white; }

/* 0,0,2,1 — two classes + one type */
nav .menu a { color: #3b82f6; }   /* wins over the rule above */

/* 0,1,1,0 — one ID + one class */
#main .card { background: white; }

/* 0,0,0,0 — universal — loses to everything */
* { box-sizing: border-box; }

/* styles.css */
p { color: red; }   /* earlier in file */
p { color: blue; }  /* later in file — this wins; paragraph text is blue */

/* inherit — force any property to inherit from parent */
.child { border: inherit; }   /* normally border would not inherit */

/* initial — reset to the CSS specification initial value */
.reset { color: initial; }    /* removes any inherited color */

/* unset — inherit if inheritable, initial if not */
.clean { all: unset; }        /* removes all default and inherited styles */

/* revert — roll back to the browser's user-agent stylesheet value */
button { all: revert; }       /* lets you re-style from the browser default */

:root {
  --color-brand:   #3b82f6;
  --spacing-md:    16px;
  --radius-base:   8px;
}

.btn {
  background:    var(--color-brand);
  padding:       var(--spacing-md);
  border-radius: var(--radius-base);
}

/* Scoped override — .dark overrides --color-brand in its subtree */
.dark {
  --color-brand: #60a5fa;
}

/* Fallback value — used if the variable is not defined */
.icon { color: var(--icon-color, currentColor); }

/* A highly specific rule */
#page header nav .btn-primary { color: white; }  /* 0,1,2,2 */

/* An !important rule wins despite low specificity */
.error { color: red !important; }  /* wins — even over the rule above */

/* What you write in card.component.css */
.card { background: white; }

/* What Angular compiles it to */
.card[_ngcontent-abc-1] { background: white; }  /* +0,0,1,0 specificity */

/* styles.css — global */
.card { background: #f1f5f9; }  /* specificity: 0,0,1,0 */

/* card.component.css — compiled */
.card[_ngcontent-abc] { background: white; }  /* specificity: 0,0,2,0 — wins */

/* Option 1: higher specificity in global styles */
:root .card { background: #f1f5f9; }  /* 0,0,1,1 — but fragile */

/* Option 2: use ViewEncapsulation.None for the component */
/* encapsulation: ViewEncapsulation.None in @Component decorator */

/* Option 3: expose a CSS custom property from the component */
/* card.component.css */
:host { --card-bg: white; }
.card { background: var(--card-bg); }

/* global styles.css — override the custom property */
app-card { --card-bg: #f1f5f9; }

// DevTools console — check effective styles
window.getComputedStyle(document.querySelector('.card')).color;

// Check all rules matching an element (not available in all browsers)
// Use DevTools Styles panel instead

/* styles.css — global baseline */
*,
*::before,
*::after {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: system-ui, -apple-system, sans-serif;
  line-height: 1.5;
  -webkit-font-smoothing: antialiased;
}

img, picture, video, canvas, svg {
  display: block;
  max-width: 100%;
}

input, button, textarea, select {
  font: inherit;  /* inherit font from body instead of browser default */
}

p, h1, h2, h3, h4, h5, h6 {
  overflow-wrap: break-word;
}

/* File 1: reset.css (loaded first, inside @layer reset) */
@layer reset {
  a { color: initial; }  /* specificity: 0,0,0,1 inside layer */
}

/* File 2: styles.css (loaded second, inside @layer base) */
@layer base {
  a { color: #3b82f6; }   /* specificity: 0,0,0,1 */
}

/* File 3: nav.css (loaded third, unlayered) */
#site-nav a         { color: #1e3a5f; }     /* 0,1,0,1 */
.nav-link           { color: #374151; }     /* 0,0,1,1 */
.nav-link.active    { color: #000; }        /* 0,0,2,1 */

/* Block */
.card { border-radius: 8px; }

/* Element — double underscore */
.card__title { font-size: 1.25rem; }
.card__body  { padding: 16px; }

/* Modifier — double hyphen */
.card--featured { border: 2px solid #3b82f6; }
.card--compact .card__body { padding: 8px; }

/* styles.css */
@layer reset, tokens, base, layout, components, utilities;

@layer tokens {
  :root {
    --color-brand: #3b82f6;
    --spacing-md: 1rem;
  }
}

@layer base {
  body { font-family: system-ui; color: #374151; }
  h1, h2, h3 { line-height: 1.25; }
}

@layer components {
  .btn { padding: 0.5rem 1rem; background: var(--color-brand); }
}

@layer utilities {
  .hidden { display: none; }
  .sr-only { position: absolute; width: 1px; clip: rect(0,0,0,0); }
}

/* Parent sets color */
.container { color: #374151; }

/* All descendants inherit color — no need to set it on every child */
.container p     { /* color is #374151 via inheritance */ }
.container span  { /* color is #374151 via inheritance */ }
.container a     { color: #3b82f6; }  /* cascade rule breaks inheritance */

/* border does NOT inherit — each element gets initial value (medium none currentColor) */
.container { border: 1px solid #e2e8f0; }
.container div { /* no border — each div starts from initial */ }

/* Remove ALL inherited AND non-inherited values — use browser defaults */
.isolated-widget { all: revert; }

/* Remove ALL values — use CSS specification initial values */
.clean-slate { all: initial; }

/* Remove ALL values — inherit or initial based on property type */
.normalized { all: unset; }
